    selector: '.version-selector',
    defaultValue: 'v2',
  },
};
```

作用：

- 在不同设备视图下同时测试组件
- 在不同版本间切换，比较组件变化
- 实时查看代码更改的效果，无需重新构建
## 3.2 Story 编写最佳实践

基于应用场景和实践经验，我们总结了以下 Story 编写规范：

### 3.2.1 组件状态全面覆盖

每个组件的 Story 应该覆盖设计稿中定义的所有变体和状态。以 Tag 组件为例：

**Figma**

![](attachment)

**Storybook Preview**

![](attachment)

**Story**

```
export const Variants: Story = {
  render: () => {
    return (
      <Stack gap={1}>
        <Tag variant="outlined">BEST SELLER</Tag>
        <Tag variant="outlined" startDecorator={<Sell />}>
          BEST SELLER
        </Tag>
        <Tag variant="solid">BEST SELLER</Tag>
        <Tag variant="solid" startDecorator={<Sell />}>
          BEST SELLER
        </Tag>
        <Tag variant="solid" color="danger" startDecorator={<OOS />}>
          OUT OF STOCK
        </Tag>
        <Tag variant="outlined" color="danger" startDecorator={<OOS />}>
          OUT OF STOCK
        </Tag>
        <Tag
          variant="solid"
          color="warning"
          startDecorator={<Info sx={{ '--fortress-icon-width': '20px', '--fortress-icon-height': '20px' }} />}
        >
          LOW IN STOCK
        </Tag>
        <Tag
          variant="outlined"
          color="warning"
          startDecorator={<Info sx={{ '--fortress-icon-width': '20px', '--fortress-icon-height': '20px' }} />}
        >
          LOW IN STOCK
        </Tag>
      </Stack>
    );
  },
};
```

这个 Story 展示了 Tag 组件的所有设计变体：

- 两种视觉样式：outlined 和 solid
- 三种颜色：默认（primary）、 danger和warning
- 有无图标装饰器的状态
**变体覆盖规范**：

1. - 根据设计稿确定需要展示的变体
2. - 确保覆盖所有视觉样式（variant）
3. - 展示所有颜色选项（color）
4. - 展示所有尺寸变体（size）
5. - 展示常见状态（如 disabled, loading）
6. - 展示带装饰器的状态（如图标、徽章）
### 3.2.2 交互行为展示

对于自定义复杂组件（如 QuantitySelector）我们使用交互测试展示和验证其行为

